// 알림 이메일 HTML 생성
const data = $input.item.json;

const conditionText = data.condition === 'above' ? '이상' : '이하';
const priceChange = ((data.current_price - parseFloat(data.target_price)) / parseFloat(data.target_price) * 100).toFixed(2);
const priceDirection = data.current_price >= parseFloat(data.target_price) ? '▲' : '▼';
const changeColor = data.condition === 'above' ? '#3fb950' : '#f85149';

const htmlBody = `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <style>
    body { font-family: 'Helvetica Neue', Arial, sans-serif; background: #0d1117; color: #e6edf3; margin: 0; padding: 0; }
    .container { max-width: 600px; margin: 40px auto; padding: 0 20px; }
    .header { background: linear-gradient(135deg, #161b22, #1c2128); padding: 30px; border-radius: 12px 12px 0 0; border-bottom: 2px solid ${changeColor}; }
    .header h1 { margin: 0; font-size: 24px; color: ${changeColor}; }
    .header p { margin: 8px 0 0; color: #8b949e; }
    .body { background: #161b22; padding: 30px; border-radius: 0 0 12px 12px; }
    .price-box { background: #0d1117; border: 1px solid #30363d; border-radius: 8px; padding: 20px; margin: 20px 0; text-align: center; }
    .current-price { font-size: 36px; font-weight: 700; color: ${changeColor}; }
    .target-price { color: #8b949e; margin-top: 8px; }
    .ai-box { background: #0d1117; border: 1px solid #388bfd33; border-radius: 8px; padding: 16px; margin: 20px 0; }
    .ai-box h3 { color: #58a6ff; font-size: 14px; margin: 0 0 10px; }
    .ai-box p { color: #cdd9e5; font-size: 14px; line-height: 1.7; margin: 0; }
    .footer { text-align: center; margin-top: 30px; color: #484f58; font-size: 12px; }
  </style>
</head>
<body>
  <div class="container">
    <div class="header">
      <h1>${priceDirection} ${data.coin_name} 가격 알림</h1>
      <p>${data.coin_symbol} | ${new Date().toLocaleString('ko-KR', {timeZone: 'Asia/Seoul'})}</p>
    </div>
    <div class="body">
      <div class="price-box">
        <div class="current-price">$${parseFloat(data.current_price).toLocaleString('en-US', {minimumFractionDigits: 2})}</div>
        <div class="target-price">
          목표가 $${parseFloat(data.target_price).toLocaleString('en-US', {minimumFractionDigits: 2})} ${conditionText} 조건 충족<br>
          목표가 대비 ${priceDirection} ${Math.abs(priceChange)}%
        </div>
      </div>
      ${data.ai_analysis ? `
      <div class="ai-box">
        <h3>🤖 EXAONE 3.5 AI 분석</h3>
        <p>${data.ai_analysis}</p>
      </div>
      ` : ''}
    </div>
    <div class="footer">
      Crypto Monitor | Django + EXAONE 3.5 (Ollama)
    </div>
  </div>
</body>
</html>`;

return [{
  json: {
    ...data,
    html_body: htmlBody,
    subject: `[Crypto Monitor] ${data.coin_symbol} ${conditionText} 알림: $${parseFloat(data.current_price).toLocaleString('en-US', {minimumFractionDigits: 2})}`,
  }
}];
